    checkCUDAError("CUDA memcpy H2D");

    time1 = get_time();

    int blockSize = 256;
    int gridSize = (count + blockSize - 1) / blockSize;

    kernel_search_points<<<gridSize, blockSize>>>(d_records,
                                                  d_knodes,
                                                  knodes_elem,
                                                  order,
                                                  maxheight,
                                                  count,
                                                  d_currKnode,
                                                  d_offset,
                                                  d_keys,
                                                  d_ans,
                                                  threadsPerBlock);
    cudaDeviceSynchronize();
    checkCUDAError("CUDA kernel_search_points");

    cudaMemcpy(ans, d_ans, sizeof(record) * (size_t)count, cudaMemcpyDeviceToHost);
    checkCUDAError("CUDA memcpy D2H");

