}

int height(node *root) {
  int h = 0;
  node *c = root;
  while (!c->is_leaf) {
    c = (node *)c->pointers[0];
    h++;
  }
  return h;
}

int path_to_root(node *root, node *child) {
  int length = 0;
  node *c = child;
  while (c != root) {
    c = c->parent;
    length++;
  }
  return length;
}

void print_tree(node *root) {
